    length回、くり返す {
        usedの末尾に 0 を追加する
        iを増やす
    }

    # Alternate between min and max
    switch = 1
    i = 0
    length回、くり返す {
        もし switch が 1 ならば、{
            # Find min - initialize with first unused value
            min_val = 0
            min_idx = 0
            first_found = 0
            j = 0
            length回、くり返す {
                もし used[j] が 0 ならば、{
                    もし first_found が 0 ならば、{
                        min_val = lst[j]
                        min_idx = j
                        first_found = 1
                    }
                    そうでなければ {
                        もし lst[j] が min_val より小さいならば、{
                            min_val = lst[j]
                            min_idx = j
                        }
                    }
                }
                jを増やす
            }
            resultの末尾に min_val を追加する
            used[min_idx] = 1
            switch = 0
        }
        そうでなければ {
            # Find max - initialize with first unused value
            max_val = 0
            max_idx = 0
            first_found = 0
            j = 0
            length回、くり返す {
                もし used[j] が 0 ならば、{
                    もし first_found が 0 ならば、{
                        max_val = lst[j]
                        max_idx = j
                        first_found = 1
                    }
                    そうでなければ {
                        もし lst[j] が max_val より大きいならば、{
                            max_val = lst[j]
                            max_idx = j
                        }
                    }
                }
                jを増やす
            }
            resultの末尾に max_val を追加する
            used[max_idx] = 1
            switch = 1
        }
        iを増やす
    }

    resultが答え
}

